// 🔥 PRIORIDADE: botão manda na frente
if ($json.intent_direto) {
  return [{
    json: {
      ...$json,
      intent: $json.intent_direto
    }
  }];
}

const entrada = $('Set Entrada').item.json;
const erpRaw  = $('POST /api/n8n/erp — Enrichment Completo').item.json;
const erp     = erpRaw.result ?? erpRaw; // normaliza resposta {ok, result}

const pItems  = (() => { try { return $('Supabase: Promessas').all(); } catch(e){ return []; }})();
const allP    = pItems.map(i=>i.json).filter(p=>p&&p.id);
const ago30   = new Date(Date.now()-30*24*60*60*1000);
const recentP = allP.filter(p=>new Date(p.created_at)>ago30&&['pending','expired'].includes(p.status)).length;
const lastFul = allP[0]?allP[0].status==='paid':true;

const F = erp.financial ?? {};
const elig = recentP<2 && (F.days_late??0)<=60 && (F.amount_due??0)<=300 && lastFul!==false;

let risk=0;
if((F.days_late??0)>60)risk+=50; else if((F.days_late??0)>30)risk+=30; else if((F.days_late??0)>15)risk+=15;
if(recentP>=2)risk+=35; else if(recentP===1)risk+=15;
if(!lastFul)risk+=25;
if((erp.tickets?.recent??0)>3)risk+=10;

const ctx = {
  ...erp,
  mensagem:        entrada.mensagem_efetiva || entrada.mensagem,
  contact_name:    entrada.contact_name,
  conversation_id: entrada.conversation_id,
  workspace_id:    entrada.workspace_id,
  promises: {
    this_month:     recentP,
    last_fulfilled: lastFul,
    eligible:       elig,
  },
  score: {
    risk:             risk>60?'ALTO':risk>30?'MEDIO':'BAIXO',
    risk_val:         risk,
    loyalty:          (erp.cliente?.months??0)>24?'FIEL':(erp.cliente?.months??0)>6?'REGULAR':'NOVO',
    promise_eligible: elig,
  },
};
return [{json: ctx}];

const ctx = $('Code: Monta Contexto').item.json;
const entrada = $('Set Entrada').item.json;
const msgRaw = ctx.mensagem ?? entrada.mensagem_efetiva ?? entrada.mensagem ?? '';
const msg = msgRaw.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').trim();
const F=ctx.financial??{}, O=ctx.connection??{}, N=ctx.network??{};
const st = (F.status??'').toUpperCase();
const inadimplente = F.is_suspended || (F.open_invoices>0 && F.days_late>5) || ['SUSPENSO','BLOQUEADO','CANCELADO','CORTADO'].includes(st);

const numMap = {'primeiro':1,'segunda':2,'segundo':2,'terceiro':3,'quarto':4,'quinto':5,'um':1,'dois':2,'tres':3,'quatro':4,'cinco':5,'o 1':1,'o 2':2,'o 3':3,'o primeiro':1,'o segundo':2,'o terceiro':3};
let contrato_selecionado = null;
const contratos = ctx.cliente?.contratos ?? ctx.contratos ?? [];
if(contratos.length > 1) {
  const directNum = msg.match(/^\s*(\d)\s*$/);
  if(directNum) { const n=parseInt(directNum[1]); if(n>=1&&n<=contratos.length) contrato_selecionado=contratos[n-1]; }
  if(!contrato_selecionado) {
    for(const [key,val] of Object.entries(numMap)) {
      if(msg.includes(key) && val>=1 && val<=contratos.length) { contrato_selecionado=contratos[val-1]; break; }
    }
  }
}

function fuzzyMatch(text, keyword, threshold) {
  if(!threshold) threshold = 0.75;
  if(text.includes(keyword)) return true;
  const words = text.split(/\s+/);
  for(const w of words) {
    if(w.length < 3 || keyword.length < 3) continue;
    if(Math.abs(w.length - keyword.length) > 2) continue;
    let matches = 0;
    const shorter = w.length <= keyword.length ? w : keyword;
    const longer = w.length > keyword.length ? w : keyword;
    for(let i=0; i<shorter.length; i++) { if(longer.includes(shorter[i])) matches++; }
    if(matches / longer.length >= threshold) return true;
  }
  return false;
}

const saudacoes = ['oi','ola','bom dia','boa tarde','boa noite','hey','eai','e ai','fala','salve','hello','hi','tudo bem','como vai','blz'];
const ehSaudacao = saudacoes.some(s => msg === s || msg.startsWith(s + ' ') || msg.startsWith(s + ',') || msg.startsWith(s + '!'));

let reclassificado = false;
let intentForcado = null;
if(F.is_suspended) intentForcado='FINANCEIRO';
else if(O.is_offline&&N.clients_offline>5) intentForcado='INCIDENTE_REGIONAL';
else if(O.is_offline&&inadimplente) { intentForcado='FINANCEIRO'; reclassificado=true; }

let intent = intentForcado || 'GERAL';
let aiResolved = false;
let aiConfidence = 0;
let keywordScore = {};

if(!intentForcado && msg.trim() && !ehSaudacao) {
  try {
    const chatbananaUrl = entrada.chatbanana_url || '';
    const historicoRaw = (() => { try { return $('GET Histórico').item.json.history ?? []; } catch(e) { return []; } })();
    const resp = await fetch(chatbananaUrl + '/api/n8n/ai/classify-intent', {
      method: 'POST',
      headers: { 'Authorization': 'Bearer chatbanana-n8n-2026', 'Content-Type': 'application/json' },
      body: JSON.stringify({
        workspace_id: ctx.workspace_id,
        mensagem: msgRaw,
        contexto: { suspenso: F.is_suspended||false, inadimplente, offline: O.is_offline||false, online: O.status==='online', faturas_abertas: F.open_invoices||0, dias_atraso: F.days_late||0 },
        historico: historicoRaw.slice(-10)
      }),
      signal: AbortSignal.timeout(10000)
    });
    const aiData = await resp.json();
    if(aiData.ok && aiData.intent && aiData.intent !== 'GERAL' && (aiData.confidence??0) >= 0.55) {
      intent = aiData.intent;
      aiResolved = true;
      aiConfidence = aiData.confidence??0;
      if(intent === 'SUPORTE_TECNICO' && inadimplente) { intent = 'FINANCEIRO'; reclassificado = true; }
    }
  } catch(aiErr) {}

  if(!aiResolved) {
    const kSup=['sem internet','sem net','caiu','offline','sem conexao','nao conecta','nao funciona','fora do ar','luz vermelha','lento','lentidao','travando','velocidade baixa','wifi fraco','sinal fraco','oscilando','piscando','reiniciar','roteador','modem','fibra','sinal','cai toda hora','instavel','ping alto','nao navega','nao abre','nao carrega','pagina nao abre','caindo','desconecta','intermitente'];
    const kCan=['cancelar','quero cancelar','desistir','quero sair','encerrar contrato','cancelamento','nao quero mais','vou cancelar','cancela meu plano','cancela minha internet','rescindir'];
    const kFin=['segunda via','fatura','boleto','pagar','pix','pagamento','devo','cobranca','debito','me manda boleto','quero pagar','manda a fatura','gerar boleto','pagar a conta','conta atrasada','quanto devo','quanto ta','quanto esta','valor da fatura','desbloqueio','desbloquear','liberar','promessa','negociar','negociacao','parcelar','acordo','renegociar'];
    const kSal=['contratar','quanto custa','novo plano','assinar','instalar internet','planos disponiveis','quero internet','instalar','instalacao','nova instalacao','mudar plano','upgrade','melhorar plano','trocar plano','qual plano','quais planos','plano melhor','velocidade maior','aumentar velocidade'];

    let sSup=0, sCan=0, sFin=0, sSal=0;
    for(const w of kSup) { if(fuzzyMatch(msg, w)) sSup++; }
    for(const w of kCan) { if(fuzzyMatch(msg, w)) sCan++; }
    for(const w of kFin) { if(fuzzyMatch(msg, w)) sFin++; }
    for(const w of kSal) { if(fuzzyMatch(msg, w)) sSal++; }

    if(sFin===0) { if(/quero\s+pagar/i.test(msg)||/me\s+(manda|envia).*boleto/i.test(msg)||/manda.*fatura/i.test(msg)||/gera.*boleto/i.test(msg)||/to\s+devendo/i.test(msg)||/ta\s+bloqueado/i.test(msg)) sFin+=2; }
    if(sSup===0) { if(/to\s+sem/i.test(msg)||/ta\s+sem/i.test(msg)||/caiu\s+tudo/i.test(msg)||/nao\s+ta\s+funcionando/i.test(msg)||/internet\s+(caiu|parou|morreu)/i.test(msg)||/nao\s+consigo\s+(acessar|conectar|navegar)/i.test(msg)) sSup+=2; }
    if(sSal===0) { if(/quero\s+contratar/i.test(msg)||/quero\s+assinar/i.test(msg)||/tem\s+plano/i.test(msg)||/qual.*preco/i.test(msg)||/quanto.*instala/i.test(msg)) sSal+=2; }
    if(sCan===0) { if(/quero\s+cancelar/i.test(msg)||/vou\s+cancelar/i.test(msg)||/nao\s+quero\s+mais/i.test(msg)||/pode\s+cancelar/i.test(msg)) sCan+=2; }

    keywordScore = { SUPORTE_TECNICO: sSup, CANCELAMENTO: sCan, FINANCEIRO: sFin, VENDAS: sSal };
    const maxScore = Math.max(sSup, sCan, sFin, sSal);
    if(maxScore > 0) {
      if(sCan===maxScore) intent='CANCELAMENTO';
      else if(sSal===maxScore && !F.is_suspended) intent='VENDAS';
      else if(sFin===maxScore && !F.is_suspended) intent='FINANCEIRO';
      else if(sSup===maxScore && inadimplente) { intent='FINANCEIRO'; reclassificado=true; }
      else if(sSup===maxScore) intent='SUPORTE_TECNICO';
      else if(sFin===maxScore) intent='FINANCEIRO';
    } else { if(O.is_offline) intent='SUPORTE_TECNICO'; }
  }
}

if(ehSaudacao && !intentForcado) {
  const sessao = (() => { try { return $('GET Sessão').item.json.session ?? {}; } catch(e) { return {}; } })();
  const fluxoAnterior = sessao.fluxoAtual ?? sessao.intent ?? '';
  if(fluxoAnterior && fluxoAnterior !== 'GERAL' && fluxoAnterior !== 'ENCERRADO') intent = fluxoAnterior;
  else intent = 'MENU';
}

if(!intent || intent === 'GERAL') {
  const sessao2 = (() => { try { return $('GET Sessão').item.json.session ?? {}; } catch(e) { return {}; } })();
  const fluxoAnterior2 = sessao2.fluxoAtual ?? sessao2.intent ?? '';
  if(fluxoAnterior2 && fluxoAnterior2 !== 'GERAL' && fluxoAnterior2 !== 'ENCERRADO') intent = fluxoAnterior2;
  else intent = 'MENU';
}

const extra = reclassificado ? { contexto_anterior:'suporte_redirecionado', motivo_redirecionamento:'cliente_inadimplente', instrucao_especial:'O cliente entrou em contato relatando problema de internet, mas identificamos que o servico esta suspenso por inadimplencia. Informe com empatia que a conexao esta suspensa e ofereca as opcoes de pagamento. Nao mencione problema tecnico.' } : {};
const contratoExtra = contrato_selecionado ? { contrato_selecionado } : {};
return [{json:{...ctx, ...extra, ...contratoExtra, intent, ai_classified: aiResolved, ai_confidence: aiConfidence, keyword_scores: keywordScore}}];

// Normaliza a resposta independente do formato retornado pelo /api/n8n/ai
const raw = $json;
const response = raw.result?.response ?? raw.response ?? raw.output ?? '';
return [{json:{
  response,
  prompt_name:  raw.prompt_name ?? raw.result?.prompt_name ?? '',
  tokens_used:  raw.tokens_used ?? raw.result?.tokens_used ?? 0,
  conversation_id: $('Set Entrada').item.json.conversation_id,
  intent: $('Code: SDR Classificação').item.json.intent ?? '',
}}];

